// // This SR latch will set Q to low when S is high and R is low, and reset to high when R is high and S is low.
module sr_latch (
    input S,
    input R,
    output reg Q,
    output reg Qn
);
    always @ (S or R) begin
        if (S && !R) begin
            Q = 1;
            Qn = 0;
        end else if (!S && R) begin
            Q = 0;
            Qn = 1;
        end else if (!S && !R) begin
            // Maintain previous state
            Q = Q;
            Qn = Qn;
        end else begin
            // Invalid state
            Q = 1'bx;
            Qn = 1'bx;
        end
    end
endmodule
